package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;
import java.lang.reflect.Field;

class CSVFormatTest {

    @Test
    void testGetIgnoreHeaderCase_DefaultFalse() {
        CSVFormat format = CSVFormat.DEFAULT;
        assertFalse(format.getIgnoreHeaderCase());
    }

    @Test
    void testGetIgnoreHeaderCase_WithTrue() {
        CSVFormat format = CSVFormat.DEFAULT.withIgnoreHeaderCase(true);
        assertTrue(format.getIgnoreHeaderCase());
    }

    @Test
    void testGetIgnoreHeaderCase_WithFalse() {
        CSVFormat format = CSVFormat.DEFAULT.withIgnoreHeaderCase(false);
        assertFalse(format.getIgnoreHeaderCase());
    }

    @Test
    void testGetIgnoreHeaderCase_ExcelFormatTrue() throws Exception {
        // EXCEL is defined as DEFAULT.withIgnoreEmptyLines(false).withAllowMissingColumnNames()
        // It does not set ignoreHeaderCase explicitly, so it should be false.
        CSVFormat format = CSVFormat.EXCEL;

        // Using reflection to verify the private field ignoreHeaderCase exists and is false
        Field field = CSVFormat.class.getDeclaredField("ignoreHeaderCase");
        field.setAccessible(true);
        boolean ignoreHeaderCaseValue = field.getBoolean(format);
        assertFalse(ignoreHeaderCaseValue);

        // Also verify via getter method
        assertFalse(format.getIgnoreHeaderCase());
    }
}
